        AND_THE_REQUIRED_ELEMENTAL_BALANCE_IS_3                                 = 10816,  -- And the required elemental balance is: [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]#.
        AND_THE_REQUIRED_ELEMENTAL_BALANCE_IS_4                                 = 10817,  -- And the required elemental balance is: [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]#.
        AND_THE_REQUIRED_ELEMENTAL_BALANCE_IS_5                                 = 10818,  -- And the required elemental balance is: [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]#.
        AND_THE_REQUIRED_ELEMENTAL_BALANCE_IS_6                                 = 10819,  -- And the required elemental balance is: [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]#.
        AND_THE_REQUIRED_ELEMENTAL_BALANCE_IS_7                                 = 10820,  -- And the required elemental balance is: [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]#.
        AND_THE_REQUIRED_ELEMENTAL_BALANCE_IS_8                                 = 10821,  -- And the required elemental balance is: [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]#.
        THERE_YOU_GO_THAT_DOESN_T_SOUND_SO                                      = 10822,  -- There you go. That doesn't sound so hard, now, does it?
        BUT_OF_COURSE_IF_YOU_LL_JUST_ALLOW                                      = 10823,  -- But of course! If you'll just allow me to inspect your % for a moment...
        YOUR_FEWELL_SUPPLY_WOULD_APPEAR_TO_BE_AS                                = 10824,  -- Your fewell supply would appear to be as follows: o o # o!# o"# o## o$# o%# o&#.
        RUNNING_LOW_WE_CAN_FILL_YOU_UP_FOR                                      = 10825,  -- Running low? We can fill you up for a nominal fee.
        REPLENISH_FEWELL_YES_NO                                                 = 10826,  -- Replenish fewell? Yes. No.
        LOOKING_FOR_A_FEWELL_FILL_UP_YOU_SAY                                    = 10827,  -- Looking for a fewell fill-up, you say? Then you've come to the right place!
        HM_WHY_YOUR_TANK_IS_ALREADY_FULL_TO                                     = 10828,  -- ...Hm? Why, your tank is already full to bursting. Come back again if you need a refill.
        NOW_LET_S_SEE_HERE_ACCORDING_TO_MY                                      = 10829,  -- Now let's see here... According to my calculations, I can fill you up to capacity for # gil. How does that sound?
        PAY_GIL_DEAL_NO_THANKS                                                  = 10830,  -- Pay # gil? Deal! No thanks.
        UNDERSTOOD_TAKE_CARE_TO_MONITOR_YOUR_RESERVES_CLOSELY                   = 10831,  -- Understood. Take care to monitor your reserves closely, lest you run out of fewell in the midst of a crucial procedure.
        I_M_AFRAID_YOU_HAVEN_T_THE_REQUISITE                                    = 10832,  -- I'm afraid you haven't the requisite gil, friend. Perhaps another time.
        EXCELLENT_NOW_WE_JUST_POP_OPEN_YOUR_HERE                                = 10833,  -- Excellent! Now we just pop open your % here, and...
        THERE_YOU_GO_FILLED_TO_THE_BRIM_WITH                                    = 10834,  -- There you go. Filled to the brim with a fresh batch of fewell! Can you smell those fumes? Mmm-mmm!
        YOUR_HAS_BEEN_FILLED_TO_CAPACITY                                        = 10835,  -- Your % has been filled to capacity!
        YOU_HAND_THE_SYNERGY_ENGINEER_GIL                                       = 10836,  -- You hand the synergy engineer # gil.
        HOW_DO_YOU_EXPECT_ME_TO_DO_THAT                                         = 10837,  -- How do you expect me to do that when your % is sitting inside a furnace, friend? You'll have to come back after you've finished synergizing.
        MATERIALS_YOU_SAY_BUT_OF_COURSE_HAVE_A                                  = 10838,  -- Materials, you say? But of course! Have a look at our selection.
        PURCHASE_SOMETHING_NOT_TODAY_GIL_GIL_GIL                                = 10839,  -- Purchase something? Not today. # : # gil. # : # gil. # : # gil.
        FOR_THAT_COMES_TO_GIL                                                   = 10840,  -- For # , that comes to # gil.
        AH_ANOTHER_DEDICATED_SYNERGIST_LOOKING_TO_REFINE_HIS                    = 10841,  -- Ah, another dedicated synergist looking to refine his/her] technique. Excellent! That motivation will serve you well.
        BUT_I_M_AFRAID_YOU_LL_NEED_EXPERIENCE                                   = 10842,  -- ...But I'm afraid you'll need [/ever so slightly more/a bit more/more/a good deal more/considerably more] experience before you're ready to benefit from my training.
        AND_YES_IT_WOULD_SEEM_YOU_RE_AT                                         = 10843,  -- And yes, it would seem you're at just the right skill level to receive my training. So, what will it be? Which technique would you like to improve?
        TRAIN_IN_WHICH_TECHNIQUE_CANCEL_FEWELL_FEEDING_CURRENT                  = 10844,  -- Train in which technique? Cancel. Fewell feeding. (Current Lv.: #) Furnace thwacking. (Current Lv.: #) Pressure handle. (Current Lv.: #) Safety lever. (Current Lv.: #) Furnace repair. (Current Lv.: #) Fewell recycling. (Current Lv.: #)
        YOU_WISH_TO_IMPROVE_YOUR_TECHNIQUE_IS_THIS                              = 10845,  -- You wish to improve your [/fewell feeding/furnace thwacking/pressure handle operation/safety lever operation/furnace repair/fewell recycling] technique. Is this correct?
        IT_WOULD_SEEM_YOUR_TECHNIQUE_ALREADY_EXCEEDS_MY                         = 10846,  -- It would seem your [/fewell feeding/furnace thwacking/pressure handle operation/safety lever operation/furnace repair/fewell recycling] technique already exceeds my own. There is no more I can teach you.
        TRAIN_IN_THIS_TECHNIQUE_YES_NO                                          = 10847,  -- Train in this technique? Yes. No.
        VERY_WELL_NOW_LISTEN_UP_WATCH_CLOSELY_AND                               = 10848,  -- Very well! Now listen up, watch closely, and try to follow along...
        SEE_YOU_TAKE_THIS_PART_HERE_AND_YES                                     = 10849,  -- ...See, you take this part here, and... Yes, yes...just like that...
        NOW_STEADY_HERE_OR_YOU_LL_BE_PICKING                                    = 10850,  -- ...Now steady here, or you'll be picking exploded furnace shrapnel out of your face for a week! Phew, that was a close one...
        AND_BY_APPLYING_COROLLARY_FIVE_OF_HILDOLF_S                             = 10851,  -- ...And by applying Corollary Five of Hildolf's Third Theory of Inverse Transfocal Equilibrium, we find that...
        CLINK_CLANK_CLUNK_ER_LET_S_TRY_THAT                                     = 10852,  -- <Clink, clank...clunk> ...Er, let's try that once more...
        SUPERB_A_QUICK_LEARNER_I_SEE_IF_ONLY                                    = 10853,  -- ...Superb! A quick learner, I see. If only all my students were as attentive as you!
        YOUR_TECHNIQUE_INCREASES_TO_LEVEL                                       = 10854,  -- Your [/fewell feeding/furnace thwacking/pressure handle operation/safety lever operation/furnace repair/fewell recycling] technique increases to level #!
        RESEARCH_INTO_THE_COMPOSITION_OF_THE_CINDER_PRODUCED                    = 10855,  -- Research into the composition of the cinder produced as a side effect of synergy just might lead to the next breakthrough in our field. Provide us with samples for analysis, and we will gladly reward your contributions.
        TRADE_IN_YOUR_CINDER_CURRENTLY_PZ_NOT_NOW                               = 10856,  -- Trade in your cinder? (Currently: # Pz) Not now. %: # Pz. %: # Pz. %: # Pz. %: # Pz. %: # Pz. %: # Pz. %: # Pz. # gil: # Pz.
        THIS_IS_WHAT_YOU_WANT_CORRECT                                           = 10857,  -- This is what you want, correct?
        MAKE_THE_EXCHANGE_YES_NO                                                = 10858,  -- Make the exchange? Yes. No.
        IT_WOULD_APPEAR_THAT_YOU_LACK_THE_NECESSARY                             = 10859,  -- It would appear that you lack the necessary quantity of cinder for that transaction.
        EXCELLENT_AND_THIS_IS_YOURS_MAY_IT_SERVE                                = 10860,  -- Excellent! And this is yours. May it serve you well!
        YOU_TRANSFERRED_PZ_OF_CINDER_TO_THE_SYNERGY                             = 10861,  -- You transferred # Pz of cinder to the synergy engineer. # Pz [remains/remain] in your possession.
        ASK_ABOUT_WHAT_NOTHING_SYNERGY_FURNACES_SYNERGY_OVERVIEW                = 10862,  -- Ask about what? Nothing. Synergy furnaces. Synergy overview. Synergy procedure. Synergy recipes. Fewell replenishment. Materials for sale. Synergy techniques. Trading cinder.
        THE_SYNERGY_FURNACES_YOU_SEE_AROUND_TOWN_ARE                            = 10863,  -- The synergy furnaces you see around town are provided as a public service by the Bastokan Institute of Synergy Research, to ensure that no synergist is ever far away from the tools of their trade.
        THE_SYNERGIST_MUST_PROVIDE_HIS_OR_HER_OWN                               = 10864,  -- The synergist must provide his or her own %, as well as any materials to be used in the synergy process. Provided those conditions are met, synergy furnaces may be used free of charge.
        NEEDLESS_TO_SAY_ONLY_ONE_PARTY_MAY_OPERATE                              = 10865,  -- Needless to say, only one party may operate any given furnace at once.
        FORTUNATELY_THERE_ARE_MULTIPLE_FURNACES_INSTALLED_THROUGHOUT_TOWN       = 10866,  -- Fortunately, there are multiple furnaces installed throughout town. If the furnace before you is already in use, please seek out an unused one elsewhere, or wait patiently for your turn.
        YOU_MAY_THINK_OF_SYNERGY_AS_AN_EVOLVED                                  = 10867,  -- You may think of synergy as an evolved form of synthesis. It is a discipline full of heretofore unimagined possibilities, but one which demands consummate skill from its practitioners.
        LIKE_SYNTHESIS_SYNERGY_INVOLVES_COMBINING_MATERIALS_ACCORDING_TO        = 10868,  -- Like synthesis, synergy involves combining materials according to a prescribed recipe to yield oft-spectacular results. The rub is that each synergy recipe also dictates a certain elemental balance that must be achieved for the procedure to be successful.
        THIS_BALANCE_IS_ACHIEVED_THROUGH_SKILLFUL_INFUSION_OF                   = 10869,  -- This balance is achieved through skillful infusion of combustible elemental crystals that we synergists call fewell. To begin the synergy process, you'll have to feed the furnace with fewell and get those flames burning!
        AS_A_GENERAL_RULE_THE_MORE_COMPLEX_THE                                  = 10870,  -- As a general rule, the more complex the recipe, the more fewell it will require. Take care to check your stock before you fire up the furnace, lest you find its flames guttering out at a crucial moment.
        WITH_THE_BELLY_OF_THE_FURNACE_ROARING_UP                                = 10871,  -- With the belly of the furnace roaring up a storm, it's time to toss in your materials and start synergizing! Keep a close eye on the balance of elements and deploy fewell as necessary. Approach the prescribed elemental balance, and your item will take form, allowing you to remove it from the furnace.
        THE_CLOSER_YOU_ARE_TO_THE_IDEAL_ELEMENTAL                               = 10872,  -- The closer you are to the ideal elemental balance, the higher the quality of your finished product will be. In synergy, it pays to be a perfectionist!
        BUT_BE_FOREWARNED_THESE_FURNACES_CAN_ONLY_SUSTAIN                       = 10873,  -- But be forewarned: these furnaces can only sustain the elemental maelstrom swirling and storming inside them for so long.
        IF_THE_FURNACE_S_DURABILITY_SHOULD_FAIL_THE                             = 10874,  -- If the furnace's durability should fail, the synergy process will be interrupted, and you will be forced to start anew.
        TAKE_HEART_THOUGH_AS_ANY_MATERIALS_INSIDE_YOUR                          = 10875,  -- Take heart, though, as any materials inside your % will remain intact. You may retrieve them or attempt the synergy process again as you see fit.
        ANY_FEWELL_CONSUMED_IN_THE_FAILED_SYNERGY_ATTEMPT                       = 10876,  -- Any fewell consumed in the failed synergy attempt, on the other hand, will be permanently lost.
        SYNERGISTS_MUST_ALSO_BE_WARY_OF_DEBRIS_BUILDUP                          = 10877,  -- Synergists must also be wary of debris buildup, an unavoidable side effect of the volatile elemental reactions that take place within the synergy furnace.
        SHOULD_TOO_MUCH_DEBRIS_BE_ALLOWED_TO_ACCUMULATE                         = 10878,  -- Should too much debris be allowed to accumulate, the contents of the furnace will become unstable, potentially leading to unpleasant explosions and eruptions. Such accidents pose considerable risk to the synergy attempt in progress, as well as the physical well-being of the synergist, so be sure to exercise due caution!
        YOU_MAY_BE_ASKING_YOURSELF_WHY_HOW_IN                                   = 10879,  -- You may be asking yourself, Why, how in the name of Hildolf am I going to oversee all of these complicated procedures and variables by myself?
        HERE_S_THE_GOOD_NEWS_YOU_DON_T                                          = 10880,  -- Here's the good news: you don't have to! For you see, synergy furnaces are designed for use by multiple operators.
        THE_MORE_COMPLEX_THE_RECIPE_THE_GREATER_LEVEL                           = 10881,  -- The more complex the recipe, the greater level of skill and hands-on manipulation it will demand. At such times, it would be in your best interest to seek out like-minded synergists and take on the challenge together.
        FINALLY_IT_WOULD_BE_REMISS_OF_ME_NOT                                    = 10882,  -- Finally, it would be remiss of me not to make mention of %, the curious substance whose properties are only now--with the emergence of synergy--becoming known to us.
        THOUGH_THERE_IS_MUCH_YET_TO_BE_LEARNED                                  = 10883,  -- Though there is much yet to be learned, our research has revealed that % may be used to bolster your equipment, if attached in a proper manner.
        MIND_YOU_IS_NOT_EASY_TO_COME_BY                                         = 10884,  -- Mind you, % is not easy to come by, and I can offer no clues as to where or how to obtain it. Should you be fortunate enough to come across some in your travels, however, I encourage you to explore its potential.
        SYNERGY_IS_NOT_A_DISCIPLINE_FOR_THE_FAINT                               = 10885,  -- Synergy is not a discipline for the faint of heart or mind, but with dedication and cooperation, there are great rewards to be reaped. May your career as a synergist prove fruitful!
        FIRST_YOU_LL_BE_WANTING_TO_CHECK_YOUR                                   = 10886,  -- First, you'll be wanting to check your fewell supply. You may do so by speaking with a synergy engineer such as myself, or by examining a synergy furnace.
        YOU_LL_BE_NEEDING_AT_LEAST_ONE_UNIT                                     = 10887,  -- You'll be needing at least one unit of fewell for each element dictated by your recipe. Without this, even the most skilled synergist cannot hope to succeed.
        SHOULD_YOUR_FEWELL_SUPPLY_BE_IN_ORDER_IT                                = 10888,  -- Should your fewell supply be in order, it's time to proceed with the synergy. If you are using one of these public synergy furnaces here, you'll need to examine it and lay claim to its use.
        YOU_MAY_THEN_DEPOSIT_YOUR_INGREDIENTS_SHOULD_THEY                       = 10889,  -- You may then deposit your ingredients. Should they correspond to a proper recipe, the synergy furnace will fire up automatically. Note that as a safety precaution, the furnace will not activate if the recipe is beyond your level of synergy skill.
        FROM_HERE_IT_BECOMES_A_RACE_AGAINST_THE                                 = 10890,  -- From here, it becomes a race against the clock! Through skilled operation of the synergy furnace, you must achieve the elemental balance prescribed by the recipe before the furnace's durability fails.
        FORTUNATELY_SYNERGY_FURNACES_ARE_OUTFITTED_WITH_A_WIDE                  = 10891,  -- Fortunately, synergy furnaces are outfitted with a wide array of features designed to aid the synergist in this demanding task. First, you'll want to confirm the current balance of elements within the furnace and compare it to your desired result.
        NEXT_YOU_CAN_BEGIN_TO_FEED_FEWELL_INTO                                  = 10892,  -- Next, you can begin to feed fewell into the furnace to gradually raise the level of elemental concentration. Feeding fewell into the furnace until the required elemental balance is achieved is the most fundamental operation of synergy.
        HOWEVER_HIGH_CONCENTRATIONS_OF_ELEMENTAL_POWER_CAN_LEAD                 = 10893,  -- However, high concentrations of elemental power can lead to volatile and unpredictable reactions. Simply adding fewell haphazardly without making the necessary adjustments is a recipe for only one thing, and that's disaster.
        IF_YOU_SENSE_THAT_THE_FURNACE_IS_ON                                     = 10894,  -- If you sense that the furnace is on the verge of elemental overload, you'll want to employ the safety lever and pressure handle to prevent an unfortunate accident from occurring.
        YOU_LL_ALSO_WANT_TO_MIND_THE_LAWS                                       = 10895,  -- You'll also want to mind the laws of elemental ascendancy and opposition. Increasing the concentration of a particular element will cause its counterpart to decrease.
        THE_FURNACE_CANNOT_SUSTAIN_ITS_POWER_INDEFINITELY_AND                   = 10896,  -- The furnace cannot sustain its power indefinitely, and will gradually lose durability as the synergy process continues. You'll need to perform periodic furnace repair should the furnace near its breaking point.
        IT_IS_ALSO_POSSIBLE_TO_RECYCLE_STREWN_FEWELL                            = 10897,  -- It is also possible to recycle strewn fewell during synergy. While this will not impact the success or failure of the process itself, it will result in a greater amount of salvageable cinder produced as a by-product.
        THIS_CINDER_IS_OF_GREAT_INTEREST_TO_OUR                                 = 10898,  -- This cinder is of great interest to our researchers back at the institute. As such, we have introduced a reward system through which quality samples can be traded in for an assortment of synergy-related wares.
        AS_MARVELOUS_AN_APPARATUS_AS_THE_SYNERGY_FURNACE                        = 10899,  -- As marvelous an apparatus as the synergy furnace may be, keep in mind that the technology is still in its infancy, and highly unstable. There may be times when accidents occur despite the best efforts of the synergist.
        FOR_YOUR_SAFETY_WE_RECOMMEND_STEPPING_AS_FAR                            = 10900,  -- For your safety, we recommend stepping as far away from the furnace as possible at the first sign of danger. Some synergists claim that giving the furnace a good thwack is also effective in preventing such accidents, but this is pure madness, if you ask me!
        YOU_WILL_ALSO_FIND_THAT_THERE_ARE_NUMEROUS                              = 10901,  -- You will also find that there are numerous techniques that can be applied to make the synergy procedure go even more smoothly.
        IN_MANY_CASES_EXPERTISE_AND_KNOWLEDGE_ACQUIRED_THROUGH                  = 10902,  -- In many cases, expertise and knowledge acquired through crafting will serve you in synergy as well. To truly master synergy, one must master crafting as well.
        NOW_LET_US_RETURN_TO_THE_SYNERGY_PROCESS                                = 10903,  -- Now let us return to the synergy process itself. As your elemental balance approaches that prescribed by the recipe, the furnace will signal you, and you may retrieve your finished product.
        IF_THE_FURNACE_IS_STILL_HOLDING_STRONG_AT                               = 10904,  -- If the furnace is still holding strong at this time, you may choose to keep working to achieve an even closer balance. The closer you come to the ideal balance, the higher the quality of your finished product will be.
        INDEED_MANY_SYNERGY_MASTERS_CONSIDER_THESE_WANING_MOMENTS               = 10905,  -- Indeed, many synergy masters consider these waning moments after the signal to be the time to really show off their skills! Why, if they manage to achieve an elemental surge...
        WHAT_S_AN_ELEMENTAL_SURGE_YOU_ASK_WHY                                   = 10906,  -- What's an elemental surge, you ask? Why, it's a miraculous phenomenon that occurs rarely--ever so rarely--upon feeding the furnace fewell.
        THE_ELEMENTS_REACT_JUST_IN_THE_RIGHT_WAY                                = 10907,  -- The elements react just in the right way, creating a miraculous reaction that brings the level of elemental concentration to exactly the desired level. Truly a boon from the Goddess for any synergist, no?
        AND_THAT_IS_THE_SYNERGY_PROCESS_IN_A                                    = 10908,  -- ...And that is the synergy process in a nutshell. There's quite a bit of information to take in, so don't hesitate to return any time for a refresher course.
        MUCH_LIKE_SYNTHESIS_TO_FASHION_ITEMS_THROUGH_SYNERGY                    = 10909,  -- Much like synthesis, to fashion items through synergy, you will need to follow a recipe. We synergy engineers are always unearthing new recipes, and are happy to share with you those suitable for your level of skill.
        UNLIKE_SYNTHESIS_HOWEVER_A_SYNERGY_RECIPE_IS_MORE                       = 10910,  -- Unlike synthesis, however, a synergy recipe is more than just a list of ingredients. There is also a required elemental balance that must be attained to achieve your desired result.
        SIMPLE_RECIPES_INVOLVE_ONLY_SMALL_DOSES_OF_A                            = 10911,  -- Simple recipes involve only small doses of a limited number of elements, but more complex ones require the synergist to skillfully juggle wide ranges of elements in extremely high concentrations.
        THE_INGREDIENTS_YOU_WILL_HAVE_TO_REMEMBER_ON                            = 10912,  -- The ingredients, you will have to remember on your own. The required elemental balance, however, may be reviewed at any time during the synergy process by observing the readings on the synergy furnace.
        IN_PARTICULAR_RECIPES_THROUGH_WHICH_THE_CURIOUS_SUBSTANCE               = 10913,  -- In particular, recipes through which the curious substance known as % can be attached to equipment are creating quite a buzz among synergistically inclined adventurers these days.
        CANNOT_BE_ATTACHED_DIRECTLY_FIRST_EQUIPMENT_MUST_BE                     = 10914,  -- % cannot be attached directly. First, equipment must be prepared by etching an aperture into which an elementally compatible piece of % can then be embedded.
        THE_TYPE_OF_APERTURE_THAT_MAY_BE_ETCHED                                 = 10915,  -- The type of aperture that may be etched will depend on the piece of equipment. There are also pieces of equipment that, alas, may not be modified at all.
        IF_YOU_ARE_CURIOUS_WHAT_MANNER_OF_APERTURE                              = 10916,  -- If you are curious what manner of aperture may be etched into a particular piece of equipment, you need only trade it to me or one of my colleagues.
        AS_A_GENERAL_RULE_THE_HIGHER_THE_LEVEL                                  = 10917,  -- As a general rule, the higher the level of the item in question, the more difficult the synergy process for creating an aperture will be.
        YOU_WILL_FIND_THAT_CERTAIN_PIECES_OF_EQUIPMENT                          = 10918,  -- You will find that certain pieces of equipment may be etched with multiple apertures. It is, however, only possible to create one aperture at a time.
        ETCHING_REQUIRES_THE_USE_OF_A_CORROSIVE_SUBSTANCE                       = 10919,  -- Etching requires the use of a corrosive substance we call mordant. Deposit mordant into a synergy furnace along with your equipment, and the process will begin.
        MY_COLLEAGUES_AND_I_HAVE_A_STOCK_OF                                     = 10920,  -- My colleagues and I have a stock of mordant available for sale. The best way to learn is to practice, so if you're curious, we encourage you to purchase some and begin experimenting!
        THE_DIFFICULTY_OF_THE_SYNERGY_PROCESS_WHEN_EMBEDDING                    = 10921,  -- The difficulty of the synergy process when embedding evolith is decided by a number of factors.
        SUCH_FACTORS_INCLUDE_THE_VARIETY_OF_APERTURE_AND                        = 10922,  -- Such factors include the variety of aperture and evolith, as well as the quantity of evolith you seek to attach. Embedding the first piece is not too difficult a task, but the second and third pieces will not go in so easily.
        TO_BEGIN_THE_EMBEDDING_PROCESS_DEPOSIT_YOUR_EVOLITH                     = 10923,  -- To begin the embedding process, deposit your evolith into the synergy furnace along with a piece of equipment with a compatible aperture.
        WHEN_ETCHING_OR_EMBEDDING_THE_REQUIRED_ELEMENTAL_BALANCE                = 10924,  -- When etching or embedding, the required elemental balance may be confirmed at any time during the synergy process, so let this be your guide.
        SHOULD_YOU_EVER_WISH_TO_REMOVE_ANY_APERTURES                            = 10925,  -- Should you ever wish to remove any apertures and embedded evolith from a piece of equipment entirely, you may do so with an ingredient we call revertant.
        TOSS_THE_REVERTANT_IN_A_SYNERGY_FURNACE_ALONG                           = 10926,  -- Toss the revertant in a synergy furnace along with your equipment, and its potent powers will restore your item to a pure and pristine state! Be warned, however, that embedded evolith will be lost forever in the process.
        AS_YOU_ARE_NO_DOUBT_ALREADY_AWARE_SYNERGY                               = 10927,  -- As you are no doubt already aware, synergy makes use of a highly combustible form of elemental crystals that we call fewell. The more complex the recipe, the greater the quantity of fewell required.
        VETERAN_SYNERGISTS_KNOW_WELL_THE_HASSLE_OF_HAVING                       = 10928,  -- Veteran synergists know well the hassle of having to constantly monitor their fewell supply and procure crystals to replenish depleted stock.
        TO_FREE_YOU_OF_SUCH_TRIFLING_BURDENS_AND                                = 10929,  -- To free you of such trifling burdens and allow you to focus your mind entirely on your art, we synergy engineers are offering a convenient fewell replenishment service!
        FOR_A_NOMINAL_FEE_CALCULATED_BASED_UPON_THE                             = 10930,  -- For a nominal fee calculated based upon the current state of your fewell reserves, we will instantly refill you to full capacity.
        THAT_S_RIGHT_ALL_ELEMENTS_IN_ONE_SIMPLE                                 = 10931,  -- That's right--all elements in one simple transaction, directly to your %! What could be easier?
        LOOKING_TO_FIRE_UP_YOUR_FURNACE_AND_ENTER                               = 10932,  -- Looking to fire up your furnace and enter the world of %? If so, you've come to the right place!
        WE_RE_PROUD_TO_OFFER_A_SUPPLY_OF                                        = 10933,  -- We're proud to offer a supply of the corrosive agent known as mordant for sale. With this, synergy newcomers can hone their skills and outfit their equipment with evolith-capable apertures in the process.
        MIND_YOU_OUR_STOCK_IS_LIMITED_TO_ONLY                                   = 10934,  -- Mind you, our stock is limited to only the most diluted, readily produced form of the stuff. You'll find that it only has the strength to etch items of relatively low level.
        ETCHING_HIGH_POWERED_EQUIPMENT_REQUIRES_THE_USE_OF                      = 10935,  -- Etching high-powered equipment requires the use of more concentrated and potent forms of mordant. As quantities are limited, we can offer these only in exchange for cinder.
        AH_SYNERGY_TECHNIQUES_THOSE_HANDY_TRICKS_OF_THE                         = 10936,  -- Ah, synergy techniques! Those handy tricks of the trade that can mean the difference between a shiny new item and a major furnace meltdown.
        MY_COLLEAGUES_AND_I_ARE_ALWAYS_EAGER_TO                                 = 10937,  -- My colleagues and I are always eager to train fellow synergists in a wide range of techniques. We can't do it all, though--you'll need to hone your synergy skill in order to benefit from our instruction.
        BEAR_IN_MIND_THAT_CERTAIN_TECHNIQUES_CAN_ONLY                           = 10938,  -- Bear in mind that certain techniques can only be imparted to students possessing specialized crafting knowledge. For example, only skilled smiths will be able to comprehend the method for more efficient fewell feeding.
        ACCOMPLISHED_GOLDSMITHS_WILL_BE_ABLE_TO_OBSERVE_THE                     = 10939,  -- Accomplished goldsmiths will be able to observe the inner workings of the furnace and stave off potential accidents. You will find that all crafting skills--even those you may not expect--may be applied in some way to support the synergy process.
        WORD_HAS_IT_THAT_THERE_ARE_ALSO_PIECES                                  = 10940,  -- Word has it that there are also pieces of equipment that can impart hidden synergy techniques to the wearer. These, too, are said to be only accessible to skilled crafters.
        THE_MORAL_OF_THE_STORY_IS_THIS_WHILE                                    = 10941,  -- The moral of the story is this: while synergy skill is important, neglect not your other crafting skills. To become a true synergy master, finding the proper balance is key.
        SYNERGY_REMAINS_A_YOUNG_DISCIPLINE_AND_RESEARCHERS_BACK                 = 10942,  -- Synergy remains a young discipline, and researchers back at the institute are burning the midnight fewell in the hopes of uncovering the next breakthrough in our field.
        RESEARCH_OF_LATE_IS_CENTERED_AROUND_THE_CINDER                          = 10943,  -- Research of late is centered around the cinder that is left behind as a by-product of each synergy operation. Their composition, it would seem, has much to teach us of the true nature of the complex elemental reactions that go on within the bellies of these furnaces.
        WE_VE_EVEN_INSTITUTED_A_REWARD_PROGRAM_FOR                              = 10944,  -- We've even instituted a reward program for adventurers willing to contribute prime samples in the name of science.
        IT_WOULD_BE_NO_EXAGGERATION_TO_SAY_THAT                                 = 10945,  -- It would be no exaggeration to say that, to us, cinder is worth more than its weight in gold! Bring it to me or my colleagues--preferably in large quantities--and you're sure to be pleased at what we can offer you in return.
        WONDERING_IF_YOUR_CAN_BE_OUTFITTED_WITH_EVOLITH                         = 10946,  -- Wondering if your % can be outfitted with evolith, are you? Well, you've come to the right place!
        A_QUICK_LOOK_AT_ITS_COMPOSITION_SHOULD_TELL                             = 10947,  -- A quick look at its composition should tell us all we need to know. Let's see here...
        CONGRATULATIONS_YOUR_CAN_INDEED_HOLD_EVOLITH_APERTURE_A                 = 10948,  -- Congratulations! Your % can indeed hold [an/another] evolith aperture. A %-shaped aperture, to be exact...
        SUITABLE_FOR_EVOLITH_OF_THE_FOLLOWING_SIZE_AND                          = 10949,  -- ...Suitable for evolith of the following size and elemental affinity: Maximum size: # / [/oo /o!/o"/o#/o$/o%/o&].
        SUITABLE_FOR_EVOLITH_OF_THE_FOLLOWING_SIZES_AND                         = 10950,  -- ...Suitable for evolith of the following sizes and elemental affinities: Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&]. Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&].
        SUITABLE_FOR_EVOLITH_OF_THE_FOLLOWING_SIZES_AND_2                       = 10951,  -- ...Suitable for evolith of the following sizes and elemental affinities: Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&]. Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&]. Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&].
        SUITABLE_FOR_EVOLITH_OF_THE_FOLLOWING_SIZES_AND_3                       = 10952,  -- ...Suitable for evolith of the following sizes and elemental affinities: Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&]. Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&]. Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&]. Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&].
        THAT_IS_ALL_SHOULD_YOU_WISH_TO_HAVE                                     = 10953,  -- That is all. Should you wish to have any other pieces of equipment analyzed, you know where to find us.
        HMM_I_M_AFRAID_YOUR_CANNOT_HOUSE_ANY                                    = 10954,  -- Hmm... I'm afraid your % cannot house any more apertures.
        ALAS_IT_S_A_SHAME_BUT_IT_APPEARS                                        = 10955,  -- ...Alas. It's a shame, but it appears your % cannot be etched.
        HMM_WHAT_S_THIS_IT_WOULD_SEEM_THAT                                      = 10956,  -- Hmm, what's this? It would seem that your % cannot be etched at this time.
        DO_YOU_LOVE_SYNERGIZING_AS_MUCH_AS_I                                    = 10957,  -- Do you love synergizing as much as I love synergizing!? 'Cause if you do, you're gonna loooooove the recipes I have for you!
        VIEW_RECIPES_FOR_WHICH_SKILL_LEVEL_ACTUALLY_NEVER                       = 10958,  -- View recipes for which skill level? Actually, never mind. Amateur. Recruit. Initiate. Novice. Apprentice. Journeyman. Craftsman. Artisan. Adept. Veteran.
        BROWSE_TO_WHICH_PAGE_CANCEL_PAGE_PAGE_PAGE                              = 10959,  -- Browse to which page? Cancel. Page [1/9/17/25/33/41/49/57/65/73/81/89/97/105/113/121]. Page [2/10/18/26/34/42/50/58/66/74/82/90/98/106/114/122]. Page [3/11/19/27/35/43/51/59/67/75/83/91/99/107/115/123]. Page [4/12/20/28/36/44/52/60/68/76/84/92/100/108/116/124]. Page [5/13/21/29/37/45/53/61/69/77/85/93/101/109/117/125]. Page [6/14/22/30/38/46/54/62/70/78/86/94/102/110/118/126]. Page [7/15/23/31/39/47/55/63/71/79/87/95/103/111/119/127]. Page [8/16/24/32/40/48/56/64/72/80/88/96/104/112/120/128]. Previous page. Next page.
        VIEW_WHICH_RECIPE_P_NONE_RETURN_TO_PAGE                                 = 10960,  -- View which recipe? ([Amateur/Recruit/Initiate/Novice/Apprentice/Journeyman/Craftsman/Artisan/Adept/Veteran], p. #). None. %. %. %. %. %. %. %. %. Return to page selection. Previous page. Next page.
        OH_THE_WHY_THAT_S_ONE_OF_MY                                             = 10961,  -- Oh, the %? Why, that's one of my favorite recipes, too! What skills does it require? Let's see here...
        WELL_LOOK_AT_THIS_ALL_YOU_NEED_IS                                       = 10962,  -- Well, look at this. All you need is a furnace and your own Goddess-given synergy skills to make that one! Ain't synergy grand?
        WAIT_NO_DON_T_TELL_ME_YOU_STRIKE                                        = 10963,  -- Wait! No, don't tell me. You strike me as a man/woman] who's looking to learn a thing or two about synergy.
        LEARN_ABOUT_SYNERGY_NOT_TODAY_TEACH_ME_JUST                             = 10964,  -- Learn about synergy? Not today. Teach me! Just give me %.
        A_LIFE_WITHOUT_INTELLECTUAL_CURIOSITY_IS_A_LIFE                         = 10965,  -- A life without intellectual curiosity is a life hardly worth living. Should your eyes one day open to this truth, you are free to return.
        I_THOUGHT_YOU_D_NEVER_ASK_SYNERGY_IS                                    = 10966,  -- I thought you'd never ask! Synergy is both an art and a science: an evolution--nay, a revolution--in synthesis.
        USING_IN_CONJUNCTION_WITH_A_SYNERGY_FURNACE_THE                         = 10967,  -- Using % in conjunction with a synergy furnace--the apparatus you see beside me--the synergist wields the power of myriad elements to fabricate a veritable host of potent items.
        WHAT_WE_CALL_SERVES_TO_DISPENSE_FEWELL_CRYSTALS                         = 10968,  -- What we call % serves to dispense fewell crystals--the lifeblood of the synergy process--whilst also protecting its contents from the volatile reactions that occur within the bowels of the furnace.
        SYNERGY_FURNACES_HAVE_BEEN_INSTALLED_THROUGHOUT_THE_CITY                = 10969,  -- Synergy furnaces have been installed throughout the city for the use of all synergists. The crucible is sufficiently compact and lightweight that you can carry it with you.
        INITIATING_THE_SYNERGY_PROCESS_IS_AS_SIMPLE_AS                          = 10970,  -- Initiating the synergy process is as simple as inserting your % into a furnace and commencing the infusion of elemental fewell.
        NEEDLESS_TO_SAY_WHAT_WILL_HAPPEN_FROM_THERE                             = 10971,  -- Needless to say, what will happen from there is not quite so simple.
        SUCCESSFUL_SYNERGY_IS_CONTINGENT_UPON_MAINTAINING_ELEMENTAL_EQUILIBRIUM = 10972,  -- Successful synergy is contingent upon maintaining elemental equilibrium. The prescribed ratio, of course, will vary depending on the artifact you are attempting to create.
        YOU_CAN_INCREASE_THE_RATIO_OF_A_PARTICULAR                              = 10973,  -- You can increase the ratio of a particular element by burning the corresponding variety of fewell.
        BUT_HEREIN_LIES_THE_RUB_SYNERGY_IS_A                                    = 10974,  -- But herein lies the rub: synergy is a still young science, and the technology we employ remains, shall we say...unstable.
        A_BIT_TOO_MUCH_FEWELL_HERE_A_WRONG                                      = 10975,  -- A bit too much fewell here, a wrong lever pulled there, and the percolating pot will explode, spitting scalding elemental guck every which way to Firesday.
        THAT_S_WHY_SMART_SYNERGISTS_SYNERGIZE_IN_NUMBERS                        = 10976,  -- That's why smart synergists synergize in numbers. Too many culinarians might spoil the broth, but when it comes to synergy, it's the more the merrier!
        AN_ASPIRING_SYNERGIST_I_SEE_IF_YOU_RE                                   = 10977,  -- An aspiring synergist, I see! If you're looking for %, you've certainly come to the right place.
        I_CAN_SELL_YOU_A_SPLENDID_ENTRY_LEVEL                                   = 10978,  -- I can sell you a splendid entry-level model for # gil. A small price to pay to embark on a lifelong journey of scientific discovery, wouldn't you say?
        GIL_PAID_IN_FULL                                                        = 10979,  -- # gil, paid in full!
        AS_PROMISED_HERE_S_YOUR_AND_BECAUSE_I                                   = 10980,  -- As promised, here's your %. And because I like your enthusiasm, I've even stocked it to the brim with fewell for you! How's that for a deal?
        THE_SYNERGIST_MUST_PROVIDE_HIS_OR_HER_OWN_2                             = 10981,  -- The synergist must provide his or her own %, as well as any materials to be used in the synergy process. Synergy furnaces themselves may be used free of charge.
        SHOULD_YOU_WISH_TO_LEARN_MORE_ABOUT_THE                                 = 10982,  -- Should you wish to learn more about the science of synergy, seek out one of the engineers stationed throughout the town.
        OH_MY_IT_S_NOT_OFTEN_WE_GET                                             = 10983,  -- Oh, my. It's not often we get to see such splendidly attirrred adventurers here in Kazham.
        I_SEE_NO_REASON_WHY_YOU_SHOULDN_T                                       = 10984,  -- I see no reason why you shouldn't be the one to receive my letter.
        WELL_TO_BE_PERRRFECTLY_HONEST_I_WAS_GOING                               = 10985,  -- Well, to be perrrfectly honest, I was going to send it off to the moogles. But between the running of Kazham and keeping its surrounds trrrouble-free, it completely escaped my mind.
        NOW_THAT_THE_LETTER_S_IN_YOUR_POSSESSION                                = 10986,  -- Now that the letter's in your possession, best you make yourself scarrrce, lest Etteh and her friends catch on.
        SHE_AND_SOME_OTHER_KITTENS_HAVE_BEEN_OBSESSED                           = 10987,  -- She and some other kittens have been obsessed with getting their paws on it, you see. The madness in their eyes is downrrright unsettling!
        KEEP_YOUR_GUARD_UP_EVEN_AFTER_YOU_VE                                    = 10988,  -- Keep your guard up even after you've returrrned to the mainland, or the Mithra there will pounce on you and make off with the letter quicker than you can say Happy Eighth Vana'versary!
        WELCOME_TO_THE_MHMU_S_PORTER_SERVICE_KUPO                               = 10989,  -- Welcome to the MHMU's porter service, kupo! Which of your burdensome belongings shall I take off your hands today?
        DO_SOMETHING_KUPO_PORTER_SERVICE_BUY_A_STORAGE                          = 10990,  -- Do something, kupo? Porter service? Buy a storage slip. No, thank you.
        IS_YOUR_GOBBIEBAG_SPLITTING_AT_THE_SEAMS_MOG                            = 10991,  -- Is your gobbiebag splitting at the seams? Mog Safe spilling over? Why, an accomplished adventurer like yourself surely has more stuff than you know what to do with.
        THAT_S_WHERE_I_COME_IN_KUPO_I                                           = 10992,  -- That's where I come in, kupo. I'll gladly hold onto your prized possessions, freeing you space to gather up even grander goodies.
        TO_MAKE_USE_OF_MY_SERVICES_FIRST_YOU                                    = 10993,  -- To make use of my services, first you'll need to buy one of these storage slips for the low, low fee of # gil.
        STORAGE_SLIPS_COME_IN_NUMEROUS_VARIETIES_KUPO_EACH                      = 10994,  -- Storage slips come in numerous varieties, kupo, each corresponding to a different type of item.
        YOU_LL_WANT_TO_PERUSE_THE_FINE_PRINT                                    = 10995,  -- You'll want to peruse the fine print closely, so you don't end up paying good gil for a scrap of parchment useless for the particular item you wish to store.
        NOT_THAT_WE_MOOGLES_WOULD_OBJECT_TO_THAT                                = 10996,  -- Not that we moogles would object to that sort of donation, kupo.
        CHOOSE_THE_ITEM_YOU_WISH_TO_ENTRUST_THEN                                = 10997,  -- Choose the item you wish to entrust, then trade it to me along with a single storage slip. I will take the item and return the slip to you, marked with an invisible seal.
        INVISIBLE_TO_YOU_AT_LEAST_IT_S_PLAIN                                    = 10998,  -- Invisible to you, at least. It's plain as day to us moogles, so don't even think of trying to pull one over on us, kupo.
        WHEN_IT_COMES_TIME_TO_RETRIEVE_YOUR_ITEM                                = 10999,  -- When it comes time to retrieve your item, just trade to me a single storage slip--any slip--once again.
        I_WILL_PRESENT_YOU_WITH_A_LIST_OF                                       = 11000,  -- I will present you with a list of all the items currently in my care, and you may choose the one you wish to withdraw. Simple as that, kupo!
        WHAT_S_MORE_NO_ADDITIONAL_TRANSACTION_FEES_WILL                         = 11001,  -- What's more, no additional transaction fees will be incurred! Pretty generous of us for a change, no?
        NOW_I_BET_YOU_RE_WONDERING_WHAT_THE                                     = 11002,  -- Now I bet you're wondering what the catch is, kupo. So as not to disappoint you, there are a few!
        FOR_ONE_ANY_SIGNED_ITEMS_WILL_LOSE_THEIR                                = 11003,  -- For one, any signed items will lose their signatures if you store them with me.
        WHY_YOU_SAY_HEY_EVEN_WE_MOOGLES_AREN                                    = 11004,  -- Why, you say? Hey, even we moogles aren't perfect! It's better for both of us if you keep your most precious possessions close at hand, kupo.
        NOW_LISTEN_UP_BECAUSE_THERE_S_ANOTHER_CATCH                             = 11005,  -- Now listen up, because there's another catch, and it's a doozy.
        IF_YOU_LOSE_YOUR_STORAGE_SLIP_I_WON                                     = 11006,  -- If you lose your storage slip, I won't be able to return your item. Ever. No ifs, ands, or buts! No I'm sorry, Mister Porter Moogle, it'll never happen again! Rules are rules, kupo, and someone has to keep them.
        LAST_BUT_NOT_LEAST_I_CAN_T_ACCEPT                                       = 11007,  -- Last, but not least, I can't accept equipment bearing Magian trial insignia.
        IF_YOU_HAVE_SUCH_AN_ITEM_THAT_YOU                                       = 11008,  -- If you have such an item that you're simply dying to entrust to me, you'll have to abandon your trial first, kupo.
        AND_THAT_S_ALL_THERE_IS_TO_IT                                           = 11009,  -- And that's all there is to it. This humble moogle can hardly wait to serve you!
        BUY_SOMETHING_P_PREVIOUS_PAGE_NEXT_PAGE_CANCEL                          = 11010,  -- Buy something? (p. #/#). Previous page. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. Next page. Cancel.
        WILL_COST_YOU_GIL_DO_WE_HAVE_A                                          = 11011,  -- % will cost you # gil. Do we have a deal, kupo?
        DEAL_KUPO_CURRENT_GIL_CHECK_STORABLE_ITEMS_DEAL                         = 11012,  -- Deal, kupo? (Current gil: #). Check storable items. Deal. No deal.
        THE_WILL_ALLOW_YOU_TO_STORE_THE_FOLLOWING                               = 11013,  -- The % will allow you to store the following items:
        ID_11014                                                                = 11014,  -- %.
        ID_11015                                                                = 11015,  -- %.
        AND_THAT_S_ALL                                                          = 11016,  -- ...and that's all.
        P_PREVIOUS_PAGE_NEXT_PAGE_CANCEL                                        = 11017,  -- % (p. #/#). Previous page. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. Next page. Cancel.
        WARNING_IF_YOU_LOSE_YOUR_WHILE_STORING_A                                = 11018,  -- Warning! If you lose your % while storing a corresponding item, you will be forever unable to retrieve that item!
        IS_THAT_I_SEE_KUPO                                                      = 11019,  -- Is that % I see, kupo?
        WHAT_WILL_YOU_DO_RETRIEVE_AN_ITEM_CONFIRM                               = 11020,  -- What will you do? Retrieve an item. Confirm storable items. Nothing.
        RETRIEVE_AN_ITEM_P_PREVIOUS_PAGE_NEXT_PAGE                              = 11021,  -- Retrieve an item? (p. #/#). Previous page. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. Next page. Cancel.
        RETRIEVE_RETRIEVE_IT_LEAVE_IT                                           = 11022,  -- Retrieve %? Retrieve it. Leave it.
        YOU_RETRIEVE_FROM_THE_PORTER_MOOGLE_S_CARE                              = 11023,  -- You retrieve % from the porter moogle's care.
        KUPO_I_M_ALREADY_TAKING_CARE_OF_THAT                                    = 11024,  -- Kupo? I'm already taking care of that item for you.
        YES_VERY_WELL_YOUR_PRECIOUS_PROPERTY_IS_SAFE                            = 11025,  -- %, yes? Very well! Your precious property is safe with me, kupo!
        OF_ITEM_IS_IT_VERY_WELL_YOUR_PRECIOUS                                   = 11026,  -- # [variety/varieties] of item, is it? Very well! Your precious property is safe with me, kupo!
        IS_THAT_A_MAGIAN_INSIGNIA_I_SEE_ON                                      = 11027,  -- Is that a Magian insignia I see on that %? You'll have to abandon your trial before I can take it off your hands, kupo.
        THAT_APPEARS_TO_BE_AUGMENTED_I_M_SORRY                                  = 11028,  -- That % appears to be augmented. I'm sorry, but I can't accept such specialized gear, kupo.
        CURIOUS_AS_TO_WHETHER_I_CAN_ACCEPT_THAT                                 = 11029,  -- Curious as to whether I can accept that item? Let me check my annals.
        WHY_YES_I_CAN_CAN_BE_STORED_WITH                                        = 11030,  -- Why, yes I can! % can be stored with %.
        WHY_IT_LOOKS_AS_IF_YOU_HAVE_LOCATED                                     = 11031,  -- Why, it looks as if you have % located in your [inventory/Mog Safe/Mog Safe 2/Mog House storage/Mog Locker/Mog Satchel/Mog Sack/Mog Case/Mog Wardrobe/Mog Wardrobe 2/Mog Wardrobe 3/Mog Wardrobe 4/Mog Wardrobe 5/Mog Wardrobe 6/Mog Wardrobe 7/Mog Wardrobe 8/Recycle Bin]!
        STORABLE_ITEM                                                           = 11032,  -- Storable item: % (#)
        STORABLE_ITEM_2                                                         = 11033,  -- Storable item: % (#)
        ID_0_1_2_3_2                                                            = 11034,  -- 0: # 1: # 2: # 3: #
        ID_4_5_6_7_2                                                            = 11035,  -- 4: # 5: # 6: # 7: #
        NO_ID                                                                   = 11036,  -- no: # id: #
        NO_ID_RES                                                               = 11037,  -- no: # id: # res: #
        TB                                                                      = 11038,  -- TB: #
        NPC_INDEX_OUT_OF_RANGE                                                  = 11039,  -- NPC index out of range.
        ERROR_CODE                                                              = 11040,  -- ERROR CODE: # / #
        YOU_NEED_TO_TALK_TO_ME_YOU_MUST                                         = 11041,  -- You need to talk to me? You must be mistaken, as I'd never play the role of a bleeding heart for a jackanapes like you.
        HM_OH_SO_YOU_RE_THAT_I_VE                                               = 11042,  -- Hm? Oh, so you're that % I've heard so much about. It certainly took you long enough. Did you fall faint from a head wound along the way?
        BUT_ENOUGH_CHIN_WAGGING_LET_US_SLICE_OPEN                               = 11043,  -- But enough chin-wagging. Let us slice open the matter at hand to reveal its pulsating innards.
        WHAT_WILL_YOU_DO_NOTHING_FOR_NOW_ASK                                    = 11044,  -- What will you do? Nothing for now. Ask a bunch of questions. Participate in Voidwatch Ops. Request debriefing. Request %. Check voidstone stock. Request reward issuance.
        YOUR_SUNDRY_QUESTIONS_FORCE_MY_THOUGHTS_TO_WANDER                       = 11045,  -- Your sundry questions force my thoughts to wander... Back to the metallic flavor of that crimson, esprit-effusing ambrosia as it assaults my tongue drop by drop...
        ANYHOW_NO_ONE_EXPLAINS_MUCH_TO_ME_THEY                                  = 11046,  -- Anyhow, no one explains much to me. They never seem to stick around long enough. Please discuss such matters with a Voidwatch Officer. They'd know more than I, and many of them have voluminous, visible veins that throb with each heartbeat, the blood inside rapping against the walls of its prison...
        THAT_FLUSHED_FACE_OF_YOURS_SPEAKS_VOLUMES_YOU                           = 11047,  -- That flushed face of yours speaks volumes. You've done fine work, indeed. Beware not to clot your adventures by lingering on Elshimo. Follow the current to Zepwell Island, then circulate back to Norg upon completing your tasks there.
        BEYOND_THAT_I_OFFER_NAUGHT_BUT_VISCERAL_CONJECTURE                      = 11048,  -- Beyond that, I offer naught but visceral conjecture. However, proving you possess a bloodstained battle record and grisly determination may gain you entry to the bowels of truth.
        OF_COURSE_YOU_D_SAY_THAT_WHY_ELSE                                       = 11049,  -- Of course you'd say that. Why else would you brave the hot Kazham sun, sizzling your flesh? Oh, how the aroma invades my nostrils, pillaging my senses until nothing but that instinctual craving for... I'm very sorry. I've terrible concentration problems. Anyway, your answer allows me to cut out the heart of this issue.
        PLEASE_CARRY_OUT_YOUR_MISSION_AT_THE_FOLLOWING                          = 11050,  -- Please carry out your mission at the following locales: Yuhtunga Jungle, Ifrit's Cauldron, and the Temple of Uggalepih.
        WORRY_NOT_ABOUT_THE_ORDER_OF_YOUR_OBJECTIVES                            = 11051,  -- Worry not about the order of your objectives, so long as you complete them by bashing in your targets' brains, exposing the smooth slime inside that leaves a thick film upon my tongue as I slurp it... Many pardons.
        NOW_DEPLOY_TO_THOSE_AREAS_I_MENTIONED_AND                               = 11052,  -- Now deploy to those areas I mentioned and make our magnificent Voidwatch proud!
        MAY_YOU_SLAY_NUMEROUS_ENEMIES_AND_SCATTER_THEIR                         = 11053,  -- May you slay numerous enemies and scatter their remains across the four directions!
        YOU_MUST_STILL_PROCEED_TO                                               = 11054,  -- You must still proceed to [the Yuhtunga Jungle/Ifrit's Cauldron/the Yuhtunga Jungle./Ifrit's Cauldron./the Temple of Uggalepih.][, Ifrit's Cauldron,/ and the Temple of Uggalepih./ and Ifrit's Cauldron.][ and the Temple of Uggalepih./]
        HOW_MANY_WOULD_YOU_LIKE_NONE_JUST_ONE                                   = 11055,  -- How many would you like? None. Just one. Fill me up!
        HERE_AS_PER_YOUR_REQUEST_PLEASE_DON_T                                   = 11056,  -- Here, as per your request. Please don't perish before depleting your stock of them.
        I_FEEL_FOOLISH_HAVING_TO_REMIND_YOU_BUT                                 = 11057,  -- I feel foolish having to remind you, but you already possess the maximum allocation of # stones. There is no need to procure more.
        OUR_STOCK_HAS_REGRETTABLY_RUN_OUT_THE_NEXT                              = 11058,  -- Our stock has regrettably run out. The next shipment should arrive in # [minute/minutes] (Earth time).
        OBTAINED_KEY_ITEM_2                                                     = 11059,  -- Obtained key item: # %!
